INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Incentive compensation management (legacy)$q$, $q$Automated calculation, modeling, and payout of sales commissions and bonuses, the original core of the Callidus product line, now continued as SAP Commissions and SAP SuccessFactors Incentive Management.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Configure, price, quote (CPQ)$q$, $q$Tools for generating accurate, rules-based sales quotes and proposals for complex product and pricing configurations, now part of SAP Sales Cloud.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Sales performance analytics$q$, $q$Dashboards and reporting that let sales operations teams track quota attainment, plan effectiveness, and compensation accuracy.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Sales content and enablement$q$, $q$A repository and delivery system for sales collateral, playbooks, and training content aimed at improving rep readiness and consistency.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Learning management$q$, $q$Course authoring and tracking tools originally used for onboarding and coaching sales teams, later absorbed into SAP SuccessFactors Learning.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Territory and quota planning$q$, $q$Modeling tools for designing sales territories and setting quotas in line with compensation plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Lead-to-cash integration$q$, $q$Positioned by SAP as connective tissue between CRM, CPQ, and ERP systems so that a deal flows from quoting through to commissioned payout without manual re-entry.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Deep, mature incentive compensation logic built up over two decades, now battle-tested inside large SAP deployments$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Tight integration with SAP's broader CRM, ERP, and HR (SuccessFactors) ecosystem for existing SAP customers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Strong historical track record serving large, complex enterprise sales organizations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Migration path onto modern SAP HANA infrastructure improves long-term scalability versus the old Oracle-based architecture$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$No longer available as an independent product; buyers must adopt the broader SAP ecosystem to access the technology$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Existing customers on the legacy architecture face a mandatory, sometimes disruptive migration to SAP HANA-based versions$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Pricing and implementation are typically enterprise-scale and quote-based, making it a poor fit for small or mid-market teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$The CallidusCloud brand and marketing presence have effectively disappeared, making independent research and reviews increasingly hard to find$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Is CallidusCloud still a company you can buy software from?$q$, $q$No. CallidusCloud stopped existing as an independent company after SAP completed its acquisition in April 2018. The technology is now sold exclusively as part of SAP's product portfolio.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$What did SAP pay for CallidusCloud?$q$, $q$SAP paid approximately 2.4 billion dollars in an all-cash deal, or 36 dollars per share, in a transaction announced in January 2018 and completed in April 2018.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$What is CallidusCloud called now?$q$, $q$Its capabilities are split across several current SAP products: SAP Commissions and SAP SuccessFactors Incentive Management (compensation), SAP Sales Cloud (CPQ and sales enablement), and SAP SuccessFactors Learning (training and coaching).$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Why did SAP acquire CallidusCloud?$q$, $q$SAP wanted immediate leadership in the lead-to-cash software category, pairing CallidusCloud's sales performance management and CPQ technology with SAP's existing CRM and ERP strength to offer a complete, cloud-based quote-to-commission workflow.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Can existing CallidusCloud customers keep using the old platform?$q$, $q$SAP has been migrating customers off the legacy Oracle-based Callidus architecture onto SAP HANA-based successor products; long-term support for the original architecture is being phased out, so existing customers need to plan a migration.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Who founded Callidus Software?$q$, $q$It was incorporated in 1996 as TallyUp Software Inc. by Andrew Swett and Scott Kitayama, renaming itself Callidus Software Inc. in 1997.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Where was CallidusCloud headquartered?$q$, $q$CallidusCloud was headquartered in Dublin, California, before the acquisition. The technology is now part of SAP SE, headquartered in Walldorf, Germany.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Enterprise sales commission automation$q$, $q$Large sales organizations use the successor SAP Commissions product to automate complex, multi-tier commission plans that would be error-prone to manage in spreadsheets.$q$, $q$Enterprise sales operations and finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$Complex quoting for configurable products$q$, $q$Manufacturers and technology vendors with highly configurable products use the CPQ capability, now under SAP Sales Cloud, to generate accurate quotes for complex bundles and pricing rules.$q$, $q$Enterprise sales and revenue operations teams$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$history$q$, $q$From TallyUp Software to a 2.4 Billion Dollar SAP Acquisition$q$, 2, ARRAY[$q$CallidusCloud's roots go back further than most people realize. The company was incorporated in Delaware in September 1996 as TallyUp Software Inc., renaming itself Callidus Software the following year to focus on enterprise incentive management: the then-novel idea of using software, rather than spreadsheets, to calculate and administer sales commissions. That niche proved durable. Callidus went public on NASDAQ in November 2003 under the ticker CALD, and over the 2000s and 2010s it broadened from pure commissions management into a fuller sales performance management and configure-price-quote suite, eventually rebranding as CallidusCloud to reflect its shift to a cloud-delivered, subscription business.$q$, $q$By fiscal year 2017, CallidusCloud was generating around 253 million dollars in annual revenue, with subscription revenue growing at roughly 31 percent, and it had built a genuine leadership position in the lead-to-cash software category alongside CPQ, sales enablement, and learning management tools. That scale and market position made it an attractive acquisition target for SAP, which announced a definitive agreement to acquire CallidusCloud for 2.4 billion dollars in cash in January 2018 and completed the deal in April 2018. SAP framed the acquisition as a way to instantly become a leader in lead-to-cash software, complementing its existing CRM and ERP strength with CallidusCloud's commissions, CPQ, and sales enablement technology.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b49866cb-4d08-4c9b-901d-a464ada3bffc', $q$life-inside-sap$q$, $q$Where CallidusCloud's Technology Lives Today$q$, 2, ARRAY[$q$Unlike some acquisitions where the acquired brand persists for years, SAP has largely retired the CallidusCloud name. Its former incentive compensation product became SAP Commissions, which SAP has since been migrating onto its SuccessFactors and SAP HANA infrastructure under the name SAP SuccessFactors Incentive Management. CallidusCloud's CPQ and sales enablement capabilities were folded into SAP Sales Cloud, and pieces of its learning and coaching technology were absorbed into the broader SAP SuccessFactors HR suite. For existing customers, this has meant a multi-year technical migration path off the original Oracle-based Callidus architecture, a transition SAP has continued to manage into the mid-2020s.$q$, $q$Practically speaking, this means CallidusCloud is not something a company can sign up for today. Anyone evaluating sales commission or CPQ software in 2026 who encounters the CallidusCloud name is looking at a legacy brand; the active product to evaluate is SAP Commissions, SAP SuccessFactors Incentive Management, or SAP Sales Cloud, sold and supported directly by SAP as part of its enterprise software portfolio and typically bundled into broader SAP customer experience or HR licensing agreements rather than sold on a standalone basis.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Framework-agnostic Web Components$q$, $q$Built on native custom elements, so Cally works identically in React, Vue, Svelte, plain HTML, or any other stack without per-framework wrapper packages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Single date, range, and multi-month selection$q$, $q$Ships calendar-date, calendar-range, and calendar-multi-view components covering the most common date-selection patterns.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Accessibility built in$q$, $q$Keyboard navigation, focus management, and ARIA semantics are designed in from the start rather than bolted on, addressing a common weak point in hand-rolled date pickers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Tiny bundle size$q$, $q$The full library comes in at roughly 8 to 9 kilobytes minified and gzipped, adding minimal weight to a page.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Unstyled by design$q$, $q$Ships with no baked-in visual styling, so it can be themed to match any design system, including Tailwind and daisyUI, without CSS override battles.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Localization and internationalization support$q$, $q$Supports rendering calendars correctly across different locales, helping teams building for international audiences.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Simple installation$q$, $q$Installable via npm or a single unpkg script tag, with no build-step requirement for basic usage.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Open-source and free$q$, $q$Fully open source with source available on GitHub, allowing teams to audit, fork, or contribute to the code.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Completely free and open source, with no licensing cost or vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Extremely small bundle size compared to most full-featured date-picker libraries$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Accessibility (keyboard navigation, screen reader support) is a core design goal, not an afterthought$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Framework-agnostic, so it works the same way across React, Vue, Svelte, and plain HTML projects$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Unstyled components make it easy to match an existing design system, especially Tailwind and daisyUI$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Requires more manual assembly than fully-styled, drop-in date-picker libraries, since input fields, buttons, and popovers must be built separately$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$No commercial support, SLA, or dedicated team behind it, since it is a community open-source project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Documentation and examples are comparatively thin next to larger, commercially-backed UI libraries$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Long-term maintenance depends on a small number of volunteer contributors rather than a funded company$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Newer than many established date-picker libraries, so the ecosystem of third-party guides and integrations is still growing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Is Cally free to use?$q$, $q$Yes. Cally is a fully open-source project with no paid tiers, licenses, or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Who created Cally?$q$, $q$Cally was created by developer Nick Williams, who previously worked on the Duet Date Picker; Cally is described as its spiritual successor.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Does Cally work with React or Vue?$q$, $q$Yes. Because Cally is built as standards-based Web Components (custom elements), it works in React, Vue, Svelte, plain HTML, and most other front-end stacks without a separate integration package.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Does Cally come pre-styled?$q$, $q$No. Cally intentionally ships without visual styling so developers can theme it to match their own design system; it is commonly paired with Tailwind CSS and daisyUI.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$How big is the Cally library?$q$, $q$Cally is very lightweight, at roughly 8 to 9 kilobytes minified and gzipped for the core components.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Is Cally accessible for screen reader and keyboard users?$q$, $q$Yes, accessibility is a core design goal: the components include keyboard navigation and ARIA attributes intended to work well with assistive technology out of the box.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Does Cally support date ranges and multiple months?$q$, $q$Yes, in addition to single-date selection, Cally includes dedicated components for date ranges (calendar-range) and multi-month calendar views (calendar-multi-view).$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$How do I install Cally in a project?$q$, $q$Cally can be installed via npm or included directly with a script tag from a CDN such as unpkg, with no required build step for basic usage.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Custom date pickers for design-system-driven apps$q$, $q$Front-end teams that already have a Tailwind, daisyUI, or custom design system use Cally's unstyled calendar primitives to build a date picker that looks native to their product rather than like a bolted-on third-party widget.$q$, $q$Front-end and product engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Accessible booking and scheduling forms$q$, $q$Developers building booking, reservation, or scheduling flows use Cally's range-selection component and built-in accessibility support to implement correct keyboard and screen-reader behavior without building it from scratch.$q$, $q$Web developers building forms and scheduling UIs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$Lightweight, framework-agnostic component libraries$q$, $q$Teams building internal component libraries or multi-framework products use Cally because it works identically regardless of the surrounding JavaScript framework, avoiding the need to maintain separate date-picker implementations per framework.$q$, $q$Platform and design-systems engineers$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$what-is-cally$q$, $q$What Cally Actually Provides$q$, 2, ARRAY[$q$Cally is not a date picker in the traditional sense of a single widget you drop into a page and configure with a few options. It is a set of low-level, unstyled calendar primitives delivered as native Web Components, meaning they work in any framework or in plain HTML without a wrapper library. The core components handle the genuinely hard parts of building a calendar: rendering the correct days for a given month, managing keyboard navigation and focus, exposing the right ARIA attributes for screen readers, and supporting range and multi-month selection. Everything else, including the text input, the toggle button, and the popover or dropdown that shows the calendar, is left to the developer to build or bring from elsewhere.$q$, $q$This design comes directly from creator Nick Williams's earlier experience building the Duet Date Picker, where he found that fully opinionated, all-in-one date pickers tend to fight against a project's existing design system. Cally's philosophy is the opposite: give developers a small, correct, accessible engine, and let them own the visual layer entirely. That trade-off means Cally requires more assembly than something like a jQuery UI datepicker or a fully-styled React component, but it also means teams are never fighting the library's default styles or trying to override deeply nested CSS just to match their brand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50dc8852-061d-48ca-aa66-b546734efaad', $q$ecosystem-fit$q$, $q$Where Cally Fits in a Modern Front-End Stack$q$, 2, ARRAY[$q$Because Cally ships as standards-based Web Components rather than framework-specific code, it fits into React, Vue, Svelte, or vanilla JavaScript projects without needing a separate integration package for each. This has made it a popular pairing with utility-first CSS frameworks: daisyUI, a popular Tailwind CSS component library, documents Cally as its recommended calendar primitive, since daisyUI can style Cally's unstyled markup directly with utility classes rather than fighting a competing design system. Community tutorials also show Cally combined with Stimulus and Alpine.js for lightweight, server-rendered applications (for example, Rails apps) that want a modern date picker without adopting a full JavaScript framework.$q$, $q$For teams evaluating Cally, the key question is not pricing or support (there is none, in the commercial sense) but fit: does your project want an accessible, framework-agnostic calendar engine that you style and wire up yourself, or do you want a fully-baked, opinionated date-picker component? Cally is squarely built for the former. Its tiny footprint, standards-based approach, and accessibility focus make it an attractive default choice for design-system-driven teams in 2026, while teams wanting a zero-assembly, drop-in widget will likely be better served by a heavier, more opinionated library.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Drag-and-drop and HTML email editor$q$, $q$Includes both a visual drag-and-drop builder and a full code editor, giving marketers and developers flexibility over email design.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$900-plus email templates$q$, $q$A large built-in template library speeds up campaign creation across industries and use cases.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Marketing automation workflows$q$, $q$Available on higher tiers, automation lets marketers build multi-step, trigger-based customer journeys rather than one-off sends.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$SMS marketing add-on$q$, $q$An optional bundle adds a dedicated phone number and text-message campaign tools that mirror the email feature set.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$eCommerce integrations$q$, $q$A dedicated add-on connects Shopify and Magento stores, unlocking purchase-behavior-based segmentation and unlimited contacts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$A/B split testing and conversion tracking$q$, $q$Built-in testing tools let marketers compare subject lines, content, or send times and tie campaigns back to conversions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Customer segmentation and dynamic content$q$, $q$Segmentation tools and, on higher tiers, dynamic content let campaigns adapt to different audience segments automatically.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Geolocation and social integration$q$, $q$Campaigns can be targeted by subscriber location and connected to social media channels for broader reach.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Long operating history and stable corporate ownership under Ziff Davis reduce the risk of sudden shutdown or platform migration$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Combines email and SMS marketing in one platform rather than requiring a separate tool for text messaging$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Includes both a visual editor and full HTML code editor, appealing to both marketers and developers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Automation and purchase-behavior features on higher tiers rival more expensive dedicated marketing automation platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Dedicated sales engineering support is available on the top-tier Advanced plan for complex sending needs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$No free plan, and the free trial requires a credit card upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Pricing rises quickly with contact list size, making it more expensive than budget competitors for larger lists$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$eCommerce and SMS capabilities are priced as separate add-ons rather than being included in core plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Entry-level Starter plan lacks the automation and behavioral reporting features that are the platform's biggest differentiators$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Being part of a large portfolio company (Ziff Davis) means Campaigner competes internally for investment against sibling brands$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Who owns Campaigner?$q$, $q$Campaigner is owned by Ziff Davis, a publicly traded digital media and software company. It has been under the same corporate lineage since j2 Global acquired its original parent, Protus IP Solutions, in 2010; j2 Global renamed itself Ziff Davis in 2021.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$How much does Campaigner cost?$q$, $q$As of 2026, core plans are priced by contact count: Starter (up to 5,000 contacts) starts around 59 dollars a month, Essential (up to 25,000 contacts) around 179 dollars a month, and Advanced (up to 100,000 contacts) around 649 dollars a month, with an approximately 18 percent discount for annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Does Campaigner offer a free plan?$q$, $q$No. Campaigner offers a 30-day free trial, but it requires credit card details to start and does not offer a permanent free tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Does Campaigner support SMS marketing?$q$, $q$Yes, via an optional SMS bundle that can be added to any plan, providing a dedicated phone number and text-campaign tools alongside email.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Can Campaigner integrate with Shopify or Magento?$q$, $q$Yes, through a paid eCommerce add-on that connects Shopify and Magento stores and also removes the contact limit on the plan it's attached to.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Is Campaigner good for beginners or only larger businesses?$q$, $q$Campaigner's entry Starter plan is usable by small businesses, but its most distinctive features (automation, purchase-behavior data, API access) are reserved for the higher-priced Advanced tier, making it best suited to businesses with an established list and marketing budget.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$How old is Campaigner as a product?$q$, $q$Campaigner launched in 1999 as part of Protus IP Solutions, making it one of the longer-running names in email marketing software.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Does Campaigner offer marketing automation, not just email blasts?$q$, $q$Yes, the Advanced plan includes automation workflows and purchase-behavior reporting, moving beyond simple autoresponders into multi-step, trigger-based customer journeys.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Mid-market email and SMS marketing$q$, $q$Established small and mid-sized businesses that have outgrown basic email tools use Campaigner's higher tiers to combine automated email journeys with native SMS campaigns in one platform.$q$, $q$Marketing teams at growing small and mid-sized businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$eCommerce lifecycle marketing$q$, $q$Online retailers use Campaigner's Shopify and Magento integrations, paired with purchase-behavior reporting, to trigger cart-abandonment, post-purchase, and win-back campaigns.$q$, $q$eCommerce marketers and store owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Agency and developer-built email campaigns$q$, $q$Agencies and developers use Campaigner's full HTML code editor and API access to build and manage highly customized campaigns for multiple clients.$q$, $q$Marketing agencies and email developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Starter$q$, $q$59 dollars per month$q$, $q$monthly (annual billing available at a discount)$q$, NULL, $q$["Up to 5,000 contacts","Drag-and-drop and HTML editor","900-plus templates","Geolocation and social integration","A/B split testing and conversion tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Essential$q$, $q$179 dollars per month$q$, $q$monthly (annual billing available at a discount)$q$, NULL, $q$["Up to 25,000 contacts","All Starter features","Dynamic content","Exclusion lists"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$Advanced$q$, $q$649 dollars per month$q$, $q$monthly (annual billing available at a discount)$q$, NULL, $q$["Up to 100,000 contacts","All Essential features","Marketing automation workflows","Purchase behavior reporting","API access","Dedicated sales engineering support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$eCommerce add-on$q$, $q$79.95 dollars per month$q$, $q$monthly, added on top of a core plan$q$, NULL, $q$["Shopify integration","Magento integration","Unlimited contacts"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$SMS bundle add-on$q$, $q$45 dollars per month$q$, $q$monthly, added on top of a core plan$q$, NULL, $q$["Dedicated phone number","Up to 1,000 monthly SMS sends","SMS campaign tools mirroring email features"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$history-ownership$q$, $q$From Protus IP Solutions to Ziff Davis$q$, 2, ARRAY[$q$Campaigner's history is longer than most people assume for a tool that reads as a fairly modern marketing platform. It launched in 1999 as a product of Protus IP Solutions, an Ottawa-based communications company that also built fax and messaging services. In 2010, j2 Global Communications, the internet services company perhaps best known for eFax, acquired Protus for a reported 213 million dollars, bringing Campaigner into its portfolio. j2 Global spent the 2010s acquiring a wide range of digital businesses, including the media company Ziff Davis in 2012. In 2021, j2 Global restructured, spinning off its cloud-services businesses into a separate public company and renaming its remaining media and software holding company Ziff Davis, after the brand it had purchased almost a decade earlier.$q$, $q$That corporate history matters for buyers mainly as a signal of stability: Campaigner has operated under essentially the same ownership lineage for well over a decade, which is unusual in the email marketing space where standalone startups frequently get acquired, merged, or shut down. It also means Campaigner sits alongside a number of other software and media brands inside Ziff Davis's portfolio rather than being a venture-backed independent company chasing its next funding round.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f6cc627-c241-4361-a9fa-09e2b287d75b', $q$pricing-positioning$q$, $q$Pricing and Where Campaigner Fits Competitively$q$, 2, ARRAY[$q$Campaigner's pricing scales by contact count across three core plans, publicly listed around 59 dollars a month for the Starter tier (up to 5,000 contacts), 179 dollars a month for Essential (up to 25,000 contacts, adding dynamic content and exclusion lists), and 649 dollars a month for Advanced (up to 100,000 contacts, adding automation workflows, purchase-behavior reporting, API access, and dedicated sales support). Two add-ons extend any tier: an eCommerce package (roughly 79.95 dollars a month) that adds Shopify and Magento integration with unlimited contacts, and an SMS bundle (roughly 45 dollars a month) that adds native text-message marketing. Annual billing brings roughly an 18 percent discount versus paying monthly.$q$, $q$This pricing places Campaigner above budget tools like Mailchimp's entry tiers or Mailerlite, but below true enterprise marketing clouds. The tradeoff buyers are making is access to more sophisticated automation workflows, dedicated onboarding support, and native SMS, in exchange for a higher starting price and a credit-card-required trial rather than a free forever plan. That makes Campaigner a more natural fit for established small and mid-sized businesses with real marketing budgets than for very early-stage startups or solo creators looking for a free entry point.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Unified client management$q$, $q$A single client record ties together CRM data, communications, documents, and billing history so firms don't need separate systems for each function.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Automated and recurring workflows$q$, $q$Firms can build repeatable, automated workflows for common engagement types (tax prep, bookkeeping, resolution cases) rather than manually tracking each task.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Client portal and e-signature$q$, $q$A secure client-facing portal supports document exchange, messaging, and e-signature collection without relying on email attachments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Time tracking, billing, and payments$q$, $q$Built-in time capture, invoicing, and payment processing let firms bill clients directly from the platform rather than a separate accounting tool.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Tax resolution and transcripts$q$, $q$Dedicated tools support tax resolution casework, including pulling and organizing IRS transcripts and notices, reflecting the founder's original background in tax resolution.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Capacity planning and reporting$q$, $q$Firms can forecast staff workload and utilization, and pull custom reports on billing, engagements, and workflow status.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$AI note-taking and automation$q$, $q$Newer AI features assist with meeting notes and are part of a broader push, funded by 2025 capital raises, to automate more firm operations.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Practice-wide document management$q$, $q$Centralized, secure document storage supports client files across engagements, with reported storage of over 6 million files per month across the customer base.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Consolidates many separate point solutions (CRM, billing, e-signature, document management, client portal) into one platform, reducing tool sprawl for firms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Purpose-built for tax and accounting workflows, including dedicated tax resolution and transcript tools rare in generic practice-management software$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Transparent, published per-user pricing tiers rather than requiring a sales call for every plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Strong reported customer base (15,000-plus practitioners) and consistently high ratings in G2's practice management categories$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Well-capitalized with continued funding rounds, suggesting ongoing investment in product development including AI features$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Per-user, per-month pricing can add up quickly for larger firms, especially once add-ons like tax workflow automation and tax resolution are included$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Higher-value automation, role-based access, and reporting features are reserved for the Plus and Premium tiers, not the entry Standard plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Shares its name with an unrelated company (Canopy Connect), which can create confusion when researching or comparing vendors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$As a single-vertical (accounting/tax) tool, it isn't useful outside that specific industry$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Add-on pricing for modules like KBA identity verification and close automation adds complexity to total cost of ownership beyond the headline per-user price$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Is Canopy the same company as Canopy Connect?$q$, $q$No. Canopy (getcanopy.com) is a practice management platform for accounting and tax firms. Canopy Connect (usecanopy.com) is a separate, unrelated company that provides an API for pulling insurance policy data from carriers. They only share a brand name.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Who founded Canopy?$q$, $q$Canopy was founded by Kurt Avarell, a former Wall Street tax attorney, in March 2014 under the original name Beanstalk, rebranding to Canopy in 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$How much does Canopy cost?$q$, $q$As of 2026, published tiers run from around 74 dollars per user per month (Standard, billed annually) up to around 149 dollars per user per month (Premium), with custom Enterprise pricing above that and various paid add-on modules.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Who is Canopy's CEO?$q$, $q$Davis Bell has served as CEO since December 2019, succeeding founder Kurt Avarell.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$What kind of firms use Canopy?$q$, $q$Canopy is built for accounting, tax, and bookkeeping firms of all sizes, from solo practitioners to large multi-location and specialized tax resolution firms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Does Canopy include tax resolution tools?$q$, $q$Yes. Because the founder's original inspiration came from tax resolution casework, Canopy includes dedicated tax resolution features, including transcript and notice management, available as a paid add-on.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$How much funding has Canopy raised?$q$, $q$Canopy has raised approximately 292 million dollars in total venture funding as of 2025, including a 70 million dollar round in April 2025, from investors including New Enterprise Associates, Tenaya Capital, and Pelion Venture Partners.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Does Canopy offer a free trial or demo?$q$, $q$Canopy directs prospective customers to book a demo and does not publish a self-serve free trial; pricing is transparent on its plans page but tailored quotes are available for Enterprise needs.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$All-in-one operations for small and mid-sized accounting firms$q$, $q$Firms replace a patchwork of separate CRM, billing, document management, and e-signature tools with a single Canopy subscription to reduce administrative overhead.$q$, $q$Small and mid-sized accounting and tax practice owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Tax resolution casework$q$, $q$Firms specializing in IRS tax resolution use Canopy's dedicated resolution tools to manage transcripts, notices, and client cases more efficiently than with generic practice management software.$q$, $q$Tax resolution specialists and enrolled agents$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Scaling firm operations with automated workflows$q$, $q$Growing firms use Canopy's automated and recurring workflow features to standardize recurring engagement types (like annual tax prep) as headcount increases, without a proportional increase in administrative work.$q$, $q$Growing multi-practitioner accounting firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Standard$q$, $q$74 dollars per user per month$q$, $q$annual (monthly billing also available at a higher rate)$q$, NULL, $q$["CRM and client management","Document management and e-signature","Client portal and secure messaging","Workflow and task tracking","Invoicing and payments"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Plus$q$, $q$109 dollars per user per month$q$, $q$annual (monthly billing also available at a higher rate)$q$, NULL, $q$["All Standard features","Automated and recurring workflows","User roles and access controls","Advanced task views and filters","Capacity planning and forecasting","Custom reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Premium$q$, $q$149 dollars per user per month$q$, $q$annual (monthly billing also available at a higher rate)$q$, NULL, $q$["All Plus features","Advanced workflows and automation","Advanced billing scenarios","Deep reporting and insights"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$Enterprise$q$, $q$Custom pricing$q$, $q$annual, custom quoted$q$, NULL, $q$["Tailored configuration for large firms","Dedicated onboarding and support","Custom integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$origin-story$q$, $q$From a Basement Side Project to a Funded Practice Management Platform$q$, 2, ARRAY[$q$Canopy's origin story is closely tied to its founder. Kurt Avarell worked as a tax attorney on Wall Street from roughly 2008 to 2010, and it was pro bono tax resolution casework during that period that exposed him to how little modern software existed to help practitioners manage tax resolution cases. Rather than accepting the status quo of spreadsheets and generic practice-management tools, Avarell began programming what would become Canopy himself, working out of his basement before formally launching the company as Beanstalk in March 2014. Beanstalk raised 2 million dollars in seed funding from New Enterprise Associates, EPIC Ventures, Deep Fork Capital, and angel investor Jim Engebretsen, giving the fledgling company enough runway to build out a real product.$q$, $q$In 2015, the company rebranded from Beanstalk to Canopy, closing an 8 million dollar Series A round, again led by NEA with participation from EPIC Ventures and Deep Fork Capital. Avarell continued to lead the company through its early growth phase before handing the CEO role to Davis Bell, a technology executive from Utah's Silicon Slopes tech corridor, in December 2019, alongside a 13 million dollar funding round. Since then, Canopy has continued to raise capital, with reported total funding of approximately 292 million dollars, including a 70 million dollar round in April 2025 that the company has said is partly aimed at building out AI capabilities across the platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23d1542d-9141-41d6-88c7-b79591f12235', $q$two-canopies$q$, $q$A Note on Naming: This Is Not Canopy Connect$q$, 2, ARRAY[$q$Because the name Canopy is shared by more than one company in the software space, it's worth being explicit about which one this profile covers. This entry describes Canopy at getcanopy.com, the practice management platform for accounting and tax firms described above. A separate and unrelated company, Canopy Connect, operates at usecanopy.com and offers a very different product: an API that lets insurtech, fintech, and insurance companies pull structured policy, premium, deductible, and declaration-page data directly from over 400 insurance carriers, often described in the market as a Plaid-style data connector for property and casualty insurance. Canopy Connect has no ownership or product relationship with the accounting-focused Canopy covered here; they simply share a brand name in different verticals.$q$, $q$This kind of naming collision is common enough in software that it's worth double-checking before signing a contract, comparing reviews, or citing pricing: search results, review sites, and even some directories can blend the two together under a single Canopy listing. For accounting and tax firms specifically, getcanopy.com is the relevant product; for developers building insurance data integrations, usecanopy.com and its Canopy Connect API are the relevant product.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$VIN decoding$q$, $q$Decodes 17-character vehicle identification numbers into structured attributes including year, make, model, trim, body type, engine, and transmission, for vehicles generally from 1990 onward.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$License plate to VIN decoding$q$, $q$Looks up a vehicle's VIN starting from a license plate number, useful for insurance, DMV-adjacent, and fleet applications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Year, make, model, and trim database$q$, $q$A structured catalog of vehicle makes, models, and trims spanning a broad historical range through current and upcoming model years.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Body, engine, color, and mileage data$q$, $q$Detailed vehicle specification data (available on higher tiers) covering body styles, engine configurations, exterior colors, and mileage figures.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$OBD-II diagnostic code lookup$q$, $q$A database of more than 9,000 OBD-II diagnostic trouble codes, useful for repair, telematics, and fleet-management applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$MSRP and market pricing data$q$, $q$Vehicle pricing data that helps applications like marketplaces and valuation tools estimate a vehicle's price range.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$REST JSON API with public documentation$q$, $q$A documented, JSON-based REST API that developers can test against a public dataset before creating an account or subscribing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$CSV and Excel data export$q$, $q$Bulk vehicle data (year, make, model, and more) can be downloaded as CSV or Excel files for offline or batch use cases.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Consolidates VIN decoding, vehicle specifications, and OBD-II codes into a single API instead of requiring multiple vendors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Transparent, publicly listed pricing with no sales call required for any tier$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Developers can prototype against a public dataset before creating an account or paying$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Metered overage billing rather than hard request caps reduces the risk of an integration breaking during traffic spikes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Broad historical data coverage extending back to early vehicle model years for basic make/model data$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$No permanently free production tier; all usable plans require an annual payment upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Detailed trim, engine, color, and mileage data is reserved for the top Premium tier, not included in the entry Base plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Very limited public information about the company itself (no disclosed founding date, headquarters, or team size), which can make enterprise vendor-risk evaluation harder$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Annual-only billing on core plans may be less flexible for teams wanting to test at low commitment$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Daily call limits (1,500 to 6,000) may be restrictive for very high-traffic production applications without factoring in overage costs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$What data does CarAPI provide?$q$, $q$CarAPI provides vehicle makes, models, trims, body styles, engines, colors, mileage data, VIN decoding, license plate to VIN decoding, MSRP and market pricing, and a database of over 9,000 OBD-II diagnostic codes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Does CarAPI have a free tier?$q$, $q$There is no permanently free production tier. Developers can prototype against a public dataset without an account, but live/production use requires one of the paid annual plans starting at 199 dollars per year.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$How much does CarAPI cost?$q$, $q$As of 2026, CarAPI has three annual plans: Base at 199 dollars per year (1,500 calls/day), Plus at 249 dollars per year (3,000 calls/day), and Premium at 299 dollars per year (6,000 calls/day, full data depth).$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$What happens if I exceed my daily API call limit?$q$, $q$CarAPI offers optional soft rate limiting with metered overage billing at roughly 0.001 dollars per call (about 1 dollar per 1,000 requests) rather than hard-blocking requests once the daily limit is reached.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Can CarAPI decode a VIN into vehicle details?$q$, $q$Yes, VIN decoding is included starting on the Base plan and returns structured data such as year, make, model, trim, body type, and engine, generally for vehicles from 1990 onward.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Is CarAPI suitable for insurance or dealership applications?$q$, $q$Yes, its combination of VIN decoding, license plate lookup, and detailed specification data is commonly used in insurance quoting, dealership inventory, fleet management, and automotive marketplace applications.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Who operates CarAPI?$q$, $q$CarAPI is operated by CarAPI LLC. The company does not publicly disclose detailed founder, headquarters, or team-size information on its marketing site.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Can I download CarAPI's data instead of calling the API live?$q$, $q$Yes, CarAPI offers CSV and Excel export of vehicle year, make, model, and related data for bulk or offline use cases.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Automotive marketplace and dealership listings$q$, $q$Marketplaces and dealership platforms use CarAPI to auto-populate accurate make, model, trim, and pricing data when a seller lists a vehicle, reducing manual data entry errors.$q$, $q$Automotive marketplace and dealership software developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Insurance quoting and underwriting$q$, $q$Insurance and insurtech applications use VIN decoding and vehicle specification data to accurately rate and underwrite auto policies without manual vehicle lookups.$q$, $q$Insurtech and insurance software developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Fleet management and vehicle diagnostics$q$, $q$Fleet management platforms use the OBD-II diagnostic code database and vehicle specification data to translate raw diagnostic codes into actionable maintenance information.$q$, $q$Fleet management and telematics developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Base$q$, $q$199 dollars per year$q$, $q$annual$q$, NULL, $q$["1,500 API calls per day","Year/make/model data (1900-2027)","Submodel data","Trim and specs (1990-2027)","VIN decoder","OBD-II codes"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Plus$q$, $q$249 dollars per year$q$, $q$annual$q$, NULL, $q$["3,000 API calls per day","All Base features","Expanded submodel data"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$Premium$q$, $q$299 dollars per year$q$, $q$annual$q$, NULL, $q$["6,000 API calls per day","Full trim, body, mileage, engine, and color data (1990-2027)","VIN decoding","Full OBD-II access"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$what-it-does$q$, $q$What CarAPI Covers$q$, 2, ARRAY[$q$CarAPI's core value proposition is consolidation: instead of stitching together separate data sources for vehicle specifications, VIN decoding, and diagnostic codes, developers get one authenticated REST API covering all of it. The year, make, and model layer spans a very wide historical range, while more detailed trim, submodel, engine, body, color, and mileage data is available from roughly the 1990 model year forward through current and near-future model years. VIN decoding takes a 17-character vehicle identification number and returns structured attributes, letting applications auto-fill vehicle details from a VIN rather than requiring manual entry, and a companion license-plate-to-VIN lookup extends that convenience further upstream. The OBD-II diagnostic code database, covering more than 9,000 codes, serves a different but related audience: repair shops, telematics platforms, and fleet management tools that need to translate a diagnostic trouble code into a human-readable description.$q$, $q$This breadth is what differentiates CarAPI from narrower competitors that focus on just VIN decoding or just a makes-and-models catalog. It also explains the plan structure: rather than gating by feature category alone, CarAPI primarily gates by daily call volume, with the higher tiers unlocking progressively deeper data (submodels on Plus, full trim and specification depth on Premium) alongside higher rate limits, so the right plan depends as much on how much data depth an application needs as on its request volume.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19a8ede5-4cfd-4432-ac47-ccee90c264f0', $q$buying-considerations$q$, $q$Pricing Structure and Who It's Built For$q$, 2, ARRAY[$q$CarAPI's pricing is unusually transparent for a data API: all three tiers and their exact daily call limits are published on its website rather than gated behind a sales call. Base, at 199 dollars a year, is aimed at developers prototyping or running lower-volume applications who mainly need core year/make/model and VIN decoding. Plus and Premium, at 249 and 299 dollars a year respectively, raise both the daily call ceiling and the depth of data available, with Premium unlocking the full specification set including engines, colors, and detailed trims. For teams that occasionally spike above their plan's daily limit, CarAPI offers metered overage billing rather than hard-blocking requests, which reduces the operational risk of an unexpected traffic spike breaking an integration.$q$, $q$Because CarAPI keeps a minimal public corporate footprint, with no disclosed founding date, headquarters, or team size, buyers evaluating it for a production system built around uptime-sensitive workflows, like real-time VIN decoding at a dealership point of sale, should treat it the way they would any smaller, specialized data vendor: verify current uptime history, support responsiveness, and data freshness directly before committing, since that operational detail isn't part of CarAPI's public marketing materials.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Agile and extreme programming practices$q$, $q$Delivery teams use pair programming, test-driven development, and iterative agile processes rather than traditional waterfall consulting methods.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Full-stack product teams$q$, $q$Engagements typically combine product management, digital design, and software engineering in one embedded team rather than separate siloed vendors.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Web and mobile application development$q$, $q$Core service offering covers custom web and mobile application design and development for both startups and established enterprises.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Product strategy and design$q$, $q$Beyond execution, Carbon Five works with clients on product discovery, UX research, and design strategy before and during development.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Embedded, collaborative delivery model$q$, $q$Teams typically work directly alongside a client's internal staff rather than delivering finished software in isolation, aiming to leave clients with stronger internal practices.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Multi-city studio presence$q$, $q$Operates studios in San Francisco, Santa Monica, New York, and Chattanooga, enabling both remote and in-person collaboration with clients across the United States.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Enterprise and startup client experience$q$, $q$A client roster spanning large enterprises (Charles Schwab, National Geographic) and venture-backed startups gives the firm range across company stages and industries.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Deep, two-decades-plus track record in agile and extreme programming practices applied to real client engagements$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Combines product management, design, and engineering in one team rather than requiring clients to coordinate separate vendors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Backed by West Monroe's scale and resources since the 2021 acquisition, adding stability without (so far) erasing the original brand and delivery model$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Diverse client base spanning both large enterprises and startups, suggesting range across project types and company stages$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Strong reputation among engineers for craft and mentorship, which can translate into higher-quality delivered code and documentation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$No published, self-serve pricing; buyers must go through a sales and scoping process to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$As a boutique-style consultancy now inside a larger parent company, some clients may find engagement processes less nimble than before the West Monroe acquisition$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Not a software product; unsuitable for buyers looking for an off-the-shelf tool rather than a custom-built engagement$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Consulting engagements are typically priced at a premium relative to offshore or lower-cost development shops, reflecting its senior-practitioner staffing model$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Availability and studio-specific expertise can vary by location, so the exact team composition depends on which studio and project you're staffed with$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Is Carbon Five a software product or a consultancy?$q$, $q$Carbon Five is a consultancy, not a software product. It provides digital product design and custom software development services to clients rather than selling a subscription tool.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Is Carbon Five still an independent company?$q$, $q$No. Carbon Five was acquired by West Monroe, a larger technology and management consulting firm, in December 2021, and now operates as Carbon Five, A West Monroe Company.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$What kind of projects does Carbon Five typically work on?$q$, $q$Carbon Five typically works on custom web and mobile application design and development, often combining product strategy, UX design, and engineering in one embedded team.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$How much does it cost to work with Carbon Five?$q$, $q$Carbon Five does not publish standard pricing; engagements are scoped and quoted individually based on project size and structure (fixed-scope build versus staff augmentation).$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Where is Carbon Five based?$q$, $q$Carbon Five was founded in San Francisco, California, in 2000, and also operates studios in Santa Monica, New York, and Chattanooga.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$What methodology does Carbon Five use?$q$, $q$Carbon Five was built around agile and extreme programming (XP) practices, including pair programming and test-driven development, from its founding in 2000.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Who are some of Carbon Five's clients?$q$, $q$Publicly referenced clients include Charles Schwab, Skype, National Geographic, and the San Francisco Museum of Modern Art, alongside numerous venture-backed startups.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Greenfield product builds for startups$q$, $q$Early and growth-stage startups engage Carbon Five to design and build a new web or mobile product from scratch, combining product strategy, design, and engineering in one team.$q$, $q$Startup founders and product leaders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Enterprise digital product modernization$q$, $q$Established companies bring in Carbon Five to modernize legacy digital products or build new customer-facing applications, leaning on the firm's agile delivery practices.$q$, $q$Enterprise product and technology leaders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$Uplifting internal engineering practices$q$, $q$Organizations use embedded Carbon Five teams to introduce stronger agile, pairing, and test-driven development practices into their own engineering culture through hands-on collaboration.$q$, $q$Engineering leaders and CTOs$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$history$q$, $q$Two Decades of Agile Product Consulting$q$, 2, ARRAY[$q$Carbon Five was founded in 2000 by a group of developers who wanted to change how software got built, adopting agile and extreme programming (XP) practices, including pair programming and test-driven development, well before those approaches became mainstream in the broader software industry. That early bet on craft and process became the firm's defining identity: rather than positioning itself as a generic staffing or bodyshop consultancy, Carbon Five built a reputation as a team of senior, deeply technical practitioners who cared as much about how software got built as what got shipped. Over time, the firm expanded its service line beyond pure engineering to include product management and digital design, reflecting a broader industry shift toward treating design, product strategy, and engineering as inseparable parts of building good software.$q$, $q$That evolution took Carbon Five from a single San Francisco studio to a multi-city firm with locations in Santa Monica, New York, and Chattanooga, working with a client list that spans large enterprises like Charles Schwab and National Geographic alongside earlier-stage, venture-backed startups. The firm also became a fairly visible presence in the software engineering community itself, publishing technical writing, sponsoring open engineering-culture profiles (such as its listing on Key Values), and building a reputation among engineers as a desirable place to work because of its emphasis on mentorship and craft.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fc042bad-c86d-4897-bb85-63e8cd464041', $q$west-monroe-era$q$, $q$Life as Part of West Monroe$q$, 2, ARRAY[$q$In December 2021, West Monroe, a larger technology and management consulting firm, acquired Carbon Five, describing the deal as a way to expand its digital product development capabilities in response to strong client demand for that kind of end-to-end product work. Since then, Carbon Five has continued operating under its own name, now presented as Carbon Five, A West Monroe Company, retaining its studio locations and much of its original team-based delivery model, while gaining access to West Monroe's larger scale, industry relationships, and operational resources.$q$, $q$For prospective clients, the practical implication is that Carbon Five today offers the boutique, senior-engineer-led delivery style it built its reputation on, backed by the resourcing and stability of a larger parent consultancy. As with any consultancy, pricing is not published; engagements are scoped individually based on project size, duration, and whether the work is structured as a fixed-scope build or an embedded staff-augmentation arrangement.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Cap table management$q$, $q$Tracks share ownership, option pools, SAFEs, convertible notes, and other equity instruments in a single digital cap table, replacing manual spreadsheet tracking.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$409A valuations$q$, $q$Offers independent 409A valuation services required to set the strike price for employee stock options in compliance with IRS rules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Equity plan and option administration$q$, $q$Handles the full lifecycle of employee equity grants, from issuance and vesting tracking to exercise and cancellation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Total compensation and benchmarking$q$, $q$Provides tools and market data to help companies design competitive cash and equity compensation packages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$QSBS tracking and attestation$q$, $q$Helps companies and shareholders document eligibility for Qualified Small Business Stock tax benefits, a valuable but easily mismanaged tax provision.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Liquidity and tender offer support$q$, $q$Provides infrastructure for running structured tender offers and other liquidity events for employees and early investors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Fund administration for venture investors$q$, $q$Offers back-office fund administration services for venture capital firms managing their own funds, extending Carta's platform beyond portfolio companies to investors themselves.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Carta Launch free tier$q$, $q$A dedicated free plan for very early-stage companies (under 25 stakeholders and under 1 million dollars raised) covering core cap table and SAFE management at no cost.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Clear market leader with the largest network of companies, investors, and shareholders, which matters for a category where investor familiarity with the tool speeds up diligence and fundraising$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Genuinely free tier (Carta Launch) removes cost as a barrier for very early-stage founders$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Broad product suite covering cap table, valuations, compensation benchmarking, and fund administration reduces the need for multiple point solutions$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Deep bench of compliance expertise (409A, QSBS) that smaller or newer competitors may not match$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Continued investment and product expansion despite the 2024 controversy suggests the core business has remained resilient$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$The January 2024 controversy over Carta's use of confidential cap table and investor data for its secondary marketplace raised real questions about data handling and conflicts of interest, even though Carta exited that specific business line$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Valuation dropped roughly 75 percent from its 2021 peak of 7.4 billion dollars, which some buyers may read as a signal of broader business or trust challenges$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Pricing for paid plans beyond the free Launch tier is not fully transparent and generally requires a custom quote$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Reported 2023 financials showed a loss (65 million dollars) alongside strong revenue (380 million dollars), raising questions about path to sustained profitability$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$As the largest incumbent, some users report a slower, more enterprise-feeling support and account-management experience compared to smaller, more nimble competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Is Carta free to use?$q$, $q$Carta offers a free plan called Carta Launch for companies with fewer than 25 stakeholders and less than 1 million dollars raised, covering core cap table and SAFE management. Larger or more complex companies move to paid plans priced by stakeholder count and features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$How much does Carta cost for a paid plan?$q$, $q$Entry-level paid plans have been reported starting around 2,800 dollars per year for smaller stakeholder counts, with growth-stage and enterprise pricing scaling into the tens of thousands of dollars annually based on custom quotes; Carta does not publish full pricing for its higher tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Who founded Carta and when?$q$, $q$Carta was founded in 2012 by Henry Ward and Manu Kumar under the name eShares, rebranding to Carta in 2017.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$What happened with Carta's 2024 controversy?$q$, $q$In January 2024, a startup CEO publicly accused Carta of using confidential cap table and investor information to solicit investors for a secondary share sale. Carta announced within about 72 hours that it would exit its secondary trading marketplace business in response.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Has Carta's valuation changed recently?$q$, $q$Yes. Carta reached a peak valuation of 7.4 billion dollars in an August 2021 Series G round led by Silver Lake, but reports indicate its valuation fell sharply, struggling to clear roughly 2 billion dollars in a 2024 secondary sale process, a decline of about 75 percent.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$What does Carta do beyond cap table management?$q$, $q$Carta also offers 409A valuations, total compensation benchmarking, QSBS attestation, secondary liquidity and tender offer support, and fund administration services for venture capital firms.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Is Carta only for startups?$q$, $q$While Carta is best known among venture-backed startups, its platform also serves later-stage private companies and, through its fund administration products, venture capital firms managing their own funds.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Is Carta the largest cap table software provider?$q$, $q$Yes, Carta is widely reported to be the market leader in cap table and equity management software, with over 50,000 companies and roughly 2.5 million shareholders on its platform as of the mid-2020s.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Startup cap table and equity management$q$, $q$Founders use Carta from incorporation onward to issue founder shares, run funding rounds, and track SAFEs and convertible notes without manual spreadsheet errors.$q$, $q$Startup founders and finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Employee equity compensation administration$q$, $q$Companies use Carta to issue, track, and communicate employee stock options and RSUs, including vesting schedules and exercise workflows, and to benchmark equity offers competitively.$q$, $q$People operations and total rewards teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Fund administration for venture capital firms$q$, $q$VC firms use Carta's fund administration products to manage their own fund accounting, investor reporting, and portfolio tracking alongside the portfolio companies already using Carta for cap tables.$q$, $q$Venture capital fund managers and fund operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Launch$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["For companies with fewer than 25 stakeholders","For companies that have raised under 1 million dollars","Cap table management","SAFE financings support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Build (entry paid tier)$q$, $q$Reported from around 2,800 dollars per year$q$, $q$annual$q$, NULL, $q$["Support for larger stakeholder counts (reported up to around 50)","Expanded cap table and compliance features versus Launch"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$Growth and Scale$q$, $q$Custom quote, reported in the range of roughly 6,000 to 77,000-plus dollars per year$q$, $q$annual$q$, NULL, $q$["Scales with stakeholder count and complexity","Compensation benchmarking and planning tools","Access to liquidity and additional compliance features"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$history$q$, $q$From eShares to the Category-Defining Cap Table Platform$q$, 2, ARRAY[$q$Carta's founding story starts with a straightforward but underserved problem: private company cap tables were, for decades, managed in error-prone spreadsheets, with real consequences when equity records didn't match reality during a fundraise, acquisition, or IPO. Henry Ward and Manu Kumar founded the company in 2012 as eShares to solve that problem with dedicated software, and it grew steadily through the 2010s as more startups adopted digital cap table management as a default rather than an afterthought. The company rebranded to Carta in 2017, reflecting an expansion of ambition beyond simple share tracking into a fuller equity management and, eventually, private-markets infrastructure platform.$q$, $q$By the early 2020s, Carta had become the category leader by a wide margin, reporting more than 50,000 companies and millions of shareholders on its platform, and had layered in adjacent products including 409A valuation services, total compensation and equity benchmarking tools, and a marketplace for secondary liquidity events like tender offers, positioning itself as core infrastructure not just for individual startups but for the venture capital ecosystem more broadly, including fund administration services for the VC firms investing in those same startups.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05dae713-e7e6-4376-9f1c-10404d9bd72a', $q$controversy-valuation$q$, $q$The 2024 Data-Use Controversy and Valuation Reset$q$, 2, ARRAY[$q$Carta's reputation took a serious hit in January 2024, when the CEO of a Finnish startup publicly alleged that Carta had used confidential information from his company's cap table, specifically, details about its investor base, to solicit those same investors for a secondary share sale unrelated to his company's wishes. Because Carta's core business depends on companies trusting it as the neutral, secure record-keeper of their most sensitive ownership data, the conflict-of-interest allegation struck at the heart of that trust relationship. Carta responded quickly, announcing within about 72 hours that it would exit its secondary trading marketplace business entirely, but the incident triggered broader scrutiny of the company's business model and practices.$q$, $q$The financial fallout was significant: Carta's valuation, which had reached 7.4 billion dollars in an August 2021 Series G round led by Silver Lake, reportedly struggled to clear even 2 billion dollars in a 2024 secondary sale process, a decline of roughly 75 percent. Public reporting also noted that Carta's core cap table business generated around 380 million dollars in revenue in 2023 while posting a 65 million dollar loss that year, adding to investor caution about the path to profitability. For buyers evaluating Carta today, this history doesn't change the product's technical capability or market dominance, but it is a reasonable and common due-diligence question, particularly for companies weighing how much sensitive ownership and investor data to entrust to a single vendor.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$CoCounsel AI legal assistant (now part of Thomson Reuters)$q$, $q$Casetext's signature product, CoCounsel, used generative AI (originally built on GPT-4) to review documents, draft research memos, prepare depositions, and analyze contracts; it now continues as CoCounsel Legal within Thomson Reuters's product line.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$SmartCite citation analysis$q$, $q$A machine-learning-driven citation analysis tool that showed how later court decisions had treated a given case, helping lawyers assess whether precedent still held.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$AI-assisted legal research$q$, $q$Combined traditional case law search with AI summarization and question-answering to speed up legal research tasks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Document review automation$q$, $q$Used AI to review large sets of documents for relevant facts, issues, or risks, reducing manual first-pass review time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Deposition preparation support$q$, $q$AI tools assisted lawyers in preparing deposition questions and materials based on case documents.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Contract analysis$q$, $q$Applied AI to analyze contracts for specific clauses, risks, or deviations from standard terms.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Self-serve, month-to-month access (historical)$q$, $q$Prior to its April 2025 shutdown, Casetext was notable for offering self-serve, month-to-month subscriptions rather than the multi-year enterprise contracts typical of Westlaw and LexisNexis.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Was an early, credible pioneer in applying generative AI (including early GPT-4 access) to real legal workflows rather than experimental use cases$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Historically offered simpler, more transparent self-serve pricing than legacy legal research incumbents$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Its acquisition and integration validated generative AI as a serious tool for legal research, accelerating adoption industry-wide$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Its core technology and team did not disappear; they now power Thomson Reuters's CoCounsel Legal product within Westlaw$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Backed by Thomson Reuters's resources and data (including Westlaw's case law database) post-acquisition, likely improving underlying research quality$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Casetext no longer exists as a standalone, purchasable product; the original self-serve platform was shut down on April 1, 2025$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Its successor, CoCounsel Legal within Westlaw Advantage, comes at a substantially higher price point (reported around 639 dollars per user per month) than Casetext's original self-serve tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Former customers with legacy promotional pricing have reported being moved to new terms without guaranteed pricing continuity$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$The current offering requires engaging with Thomson Reuters's more traditional, contract-based sales process rather than Casetext's old self-serve signup$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Anyone researching Casetext today needs to actively account for the acquisition and shutdown, since a meaningful amount of older online content still describes it as an active, independent product$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Does Casetext still exist as a product?$q$, $q$No, not as a standalone product. Thomson Reuters shut down the original Casetext platform on April 1, 2025, after acquiring the company in 2023. Its technology now operates as CoCounsel Legal within Thomson Reuters's Westlaw product line.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Who acquired Casetext and for how much?$q$, $q$Thomson Reuters acquired Casetext for 650 million dollars in cash, in a deal announced in June 2023 and completed on August 17, 2023.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$What was CoCounsel?$q$, $q$CoCounsel was Casetext's AI legal assistant, launched in March 2023 and built on OpenAI's GPT-4, capable of document review, legal research memo drafting, deposition preparation, and contract analysis.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$What happens if I search for casetext.com today?$q$, $q$As of 2026, casetext.com redirects to Thomson Reuters's CoCounsel hub, reflecting the shutdown of the standalone Casetext platform in April 2025.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Who founded Casetext?$q$, $q$Casetext was founded in 2013 by Jake Heller, Pablo Arredondo, and Laura Safdie, launching out of Y Combinator with roughly 1.8 million dollars in seed funding.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$What replaced Casetext after the shutdown?$q$, $q$Thomson Reuters launched CoCounsel Legal in August 2025 as the successor product, integrated into its Westlaw ecosystem rather than offered as an independent self-serve tool the way Casetext was.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$How much did Casetext cost before it shut down?$q$, $q$Standalone Casetext research plans were reported at roughly 65 to 99 dollars per user per month, with CoCounsel itself available separately at either 500 dollars per month for unlimited use or 50 dollars per task.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$How much does the current CoCounsel Legal product cost?$q$, $q$The closest current equivalent, Westlaw Advantage with CoCounsel Essentials, has been reported at around 639 dollars per user per month for a solo practitioner on a one-year term, though Thomson Reuters generally quotes pricing individually.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$AI-assisted legal research (historical Casetext use case)$q$, $q$Law firms and legal departments used Casetext for case law research and citation analysis at a lower cost and with more flexible terms than legacy legal databases; this workflow now runs through CoCounsel Legal within Westlaw.$q$, $q$Litigators and legal researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$Document review and contract analysis via CoCounsel$q$, $q$Legal teams use the CoCounsel technology, now part of Thomson Reuters, to accelerate document review, contract analysis, and deposition preparation using generative AI.$q$, $q$Corporate legal departments and litigation support teams$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$history$q$, $q$From a Y Combinator Legal Research Startup to a 650 Million Dollar Acquisition$q$, 2, ARRAY[$q$Casetext was founded in 2013 by Jake Heller, Pablo Arredondo, and Laura Safdie, launching out of Y Combinator in October of that year with roughly 1.8 million dollars in seed funding and a mission the founders often described as making the law free and understandable. In its first decade, Casetext built a legal research product that undercut the pricing and rigidity of incumbents like Westlaw and LexisNexis, adding features like SmartCite, which used machine learning to analyze how later court decisions treated a given case, and growing its customer base past 10,000 law firms and corporate legal departments by the early 2020s.$q$, $q$The company's trajectory changed dramatically in March 2023 with the launch of CoCounsel, an AI legal assistant built on OpenAI's GPT-4 model. Casetext was one of a small number of companies given early access to GPT-4 specifically to explore legal applications, and CoCounsel's ability to review documents, draft research memos, and analyze contracts using generative AI generated significant industry attention at a moment when generative AI was just becoming a mainstream business topic. That momentum led directly to Thomson Reuters's acquisition offer: announced in June 2023 and closed in August 2023, Thomson Reuters paid 650 million dollars in cash for Casetext, one of the largest legal technology acquisitions on record and one of the largest AI-related acquisitions of that period.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('85b579b1-50a2-45ad-9e3b-d15e5d306869', $q$current-status$q$, $q$Where Casetext's Technology Lives in 2026$q$, 2, ARRAY[$q$For roughly a year and a half after the acquisition, Thomson Reuters kept Casetext running largely as it had operated before, as a self-serve, month-to-month product with published per-seat pricing, a notable contrast to the multi-year enterprise contracts typical of Westlaw and LexisNexis. That arrangement ended on April 1, 2025, when Thomson Reuters formally shut down the standalone Casetext platform, migrating existing customers onto its broader product line. In August 2025, Thomson Reuters launched CoCounsel Legal as the successor, fully integrated into its Westlaw ecosystem rather than offered as an independent, self-serve product the way Casetext had been.$q$, $q$The practical effect for anyone researching Casetext today is that it is a retired brand rather than an active product. Visiting casetext.com now redirects to Thomson Reuters's CoCounsel hub, and the closest comparable offering, Westlaw Advantage with CoCounsel Essentials, comes at a meaningfully higher price point (reported around 639 dollars per user per month for a solo practitioner) and under more traditional term-contract conditions than Casetext's original self-serve pricing. Some former Casetext customers who had locked in older promotional or for-life pricing have publicly reported being shifted onto new fixed-term Thomson Reuters pricing without assurance that those legacy rates would be honored going forward, which is a relevant consideration for anyone still referencing Casetext's old pricing as current.$q$]::text[], 1);
