-- в”Ђв”Ђ Campaigner в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Campaigner is an email and SMS marketing automation platform aimed at mid-market businesses that have outgrown basic email tools. Originally launched in 1999 and owned since 2010 by j2 Global (renamed Ziff Davis in 2021), it offers drag-and-drop email design, marketing automation workflows, and add-on eCommerce and SMS capabilities on subscriber-based pricing tiers.$q$, short_description),
  pricing_model = COALESCE($q$Subscription, tiered by contact/subscriber count, billed monthly or annually$q$, pricing_model),
  starting_price = COALESCE($q$From around 59 dollars per month for up to 5,000 contacts (Starter plan, billed monthly)$q$, starting_price),
  founded_year = COALESCE(1999, founded_year),
  company_size = COALESCE($q$Operates as part of Ziff Davis, a publicly traded digital media and technology company with thousands of employees across its portfolio brands$q$, company_size),
  headquarters = COALESCE($q$Ottawa, Canada (original base as Protus IP Solutions); now operated under Ziff Davis, headquartered in New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Campaigner Review 2026: Pricing, Features, and Who It Is Owned By$q$, seo_title),
  seo_meta_description = COALESCE($q$Campaigner is a mid-market email and SMS marketing automation platform now owned by Ziff Davis. See 2026 pricing, features, pros and cons before you sign up.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Campaigner is an email and SMS marketing automation platform positioned for businesses that have outgrown entry-level tools like basic newsletter senders but are not ready for the cost and complexity of enterprise platforms such as Salesforce Marketing Cloud. The product traces back to 1999, when it launched as part of Protus IP Solutions, an Ottawa, Canada-based communications company. Protus was acquired in 2010 by j2 Global Communications (best known at the time for eFax and other internet services) in a deal reportedly worth around 213 million dollars, and Campaigner has remained under that corporate umbrella ever since. j2 Global restructured its business in 2021, spinning off its cloud-services division and renaming the parent holding company Ziff Davis, after the digital media company j2 had acquired back in 2012. As a result, Campaigner today operates as one of several marketing and software brands inside the publicly traded Ziff Davis portfolio, rather than as an independent company. On the product side, Campaigner functions as a fairly full-featured email marketing suite: every plan includes a drag-and-drop editor alongside a full HTML code editor, access to a library of more than 900 pre-built templates, geolocation-based targeting, social media integration, conversion tracking, A/B split testing, autoresponders, customer segmentation, and standard email performance reporting. Pricing is structured around subscriber list size across three core tiers: a Starter plan supporting up to 5,000 contacts, an Essential plan supporting up to 25,000 contacts that adds dynamic content and exclusion-list capabilities, and an Advanced plan supporting up to 100,000 contacts that layers on marketing automation workflows, purchase-behavior reporting, API access, and dedicated sales engineering support. Businesses that need more can add two optional bundles: an eCommerce add-on that unlocks Shopify and Magento integrations along with unlimited contacts, and an SMS bundle that adds a dedicated phone number and text-message sending on top of any core plan. Customers can choose monthly or annual billing, with annual commitments saving roughly 18 percent versus paying month to month, and Campaigner offers a 30-day free trial, though it requires a credit card to start. Where Campaigner tends to differentiate itself from lighter tools like Mailchimp is in its automation depth (workflow-based journeys rather than simple autoresponders), its inclusion of SMS as a native add-on, and its willingness to provide hands-on sales engineering support for larger senders, all of which push it toward the higher end of small-to-mid-market pricing rather than competing purely on a free tier. Because it has been owned by the same corporate parent for over a decade, Campaigner is a mature, stable product rather than an early-stage startup tool, though buyers should expect the more traditional, sales-assisted onboarding common to established SaaS brands of its type rather than a fully self-serve, product-led experience.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2f6cc627-c241-4361-a9fa-09e2b287d75b';

