-- в”Ђв”Ђ Casetext в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Casetext was an AI-powered legal research platform, best known for its CoCounsel AI legal assistant, acquired by Thomson Reuters for 650 million dollars in cash in 2023. As of 2026, Casetext no longer exists as a standalone product: Thomson Reuters retired the original casetext.com platform on April 1, 2025, and its technology now lives on as CoCounsel Legal, sold alongside Westlaw as part of Thomson Reuters's core legal research suite.$q$, short_description),
  pricing_model = COALESCE($q$Formerly direct self-serve subscription; now sold only as part of Thomson Reuters's Westlaw and CoCounsel Legal bundles$q$, pricing_model),
  starting_price = COALESCE($q$No longer available standalone; comparable current offering (Westlaw Advantage with CoCounsel Essentials) has been reported around 639 dollars per user per month for a solo practitioner on a 1-year term$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Formerly an independent company with roughly 10,000-plus law firm and corporate legal customers before acquisition; now fully absorbed into Thomson Reuters, a global company with tens of thousands of employees$q$, company_size),
  headquarters = COALESCE($q$Formerly San Francisco, California, United States; now part of Thomson Reuters, headquartered in Toronto, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Casetext Review 2026: What Happened After the Thomson Reuters Acquisition$q$, seo_title),
  seo_meta_description = COALESCE($q$Casetext pioneered AI legal research with CoCounsel before Thomson Reuters bought it for 650 million dollars. See what happened to it and where its tools live now.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Casetext was a San Francisco-based legal research startup, founded in 2013 by Jake Heller, Pablo Arredondo, and Laura Safdie, that built its early reputation on offering a lower-cost, AI-assisted alternative to legacy legal research giants like Westlaw and LexisNexis. Backed by Y Combinator and roughly 1.8 million dollars in early seed funding, Casetext launched in October 2013 and steadily built out research tools including its SmartCite citation analysis feature, eventually growing to serve more than 10,000 law firms and corporate legal departments. The company's defining moment came in March 2023, when it launched CoCounsel, an AI legal assistant built on OpenAI's GPT-4 (Casetext was among a small group of companies granted early access to GPT-4 specifically to build legal applications), which could review documents, draft legal research memos, prepare deposition materials, and analyze contracts using generative AI rather than traditional keyword search. CoCounsel's rapid adoption and the broader excitement around generative AI in legal work made Casetext an extremely attractive acquisition target: Thomson Reuters announced in June 2023 that it would acquire Casetext for 650 million dollars in cash, a deal that closed on August 17, 2023, and that was, at the time, one of the largest acquisitions in the legal technology sector and among the largest AI and machine learning acquisitions of the first half of 2023. Following the acquisition, Thomson Reuters initially kept Casetext operating as a distinct, self-serve, month-to-month product, which stood out because it didn't require the multi-year enterprise contracts typical of Westlaw and LexisNexis; reported pricing during that period ran roughly 65 to 99 dollars per user per month for standalone Casetext research plans, with CoCounsel itself offered separately at either 500 dollars per month for unlimited use or 50 dollars per task on a pay-as-you-go basis. That standalone era did not last: Thomson Reuters shut down the original Casetext platform on April 1, 2025, migrating existing subscribers onto Thomson Reuters's core products, before formally launching CoCounsel Legal in August 2025 as an integrated part of the Westlaw ecosystem rather than a separate self-serve product. As of 2026, casetext.com redirects to Thomson Reuters's CoCounsel hub, and the closest equivalent to what Casetext used to offer, self-serve legal research plus AI assistance without a sales call, is Westlaw Advantage bundled with CoCounsel Essentials, reported at around 639 dollars per user per month for a solo practitioner on a one-year term, a meaningfully higher price point and a more traditional enterprise-style commitment than Casetext's original month-to-month model. For anyone researching Casetext today, it's important to be accurate about its current status: it is not an active, purchasable product. It is a retired brand whose technology, team, and customer base were absorbed into Thomson Reuters's Westlaw and CoCounsel Legal offerings, and legacy Casetext customers who held older promotional or for-life pricing have reported being moved onto new, fixed-term Thomson Reuters pricing without a guaranteed renewal rate at the old terms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '85b579b1-50a2-45ad-9e3b-d15e5d306869';

